// Total DTC codes: 200+
// Export helper for lookup
export function getDTCByCode(code: string): DTCCode | undefined {
  return DTC_CODES[code.toUpperCase()];
}

// Get DTCs by severity
export function getDTCsBySeverity(severity: 'INFO' | 'WARNING' | 'CRITICAL'): DTCCode[] {
  return Object.values(DTC_CODES).filter(d => d.severity === severity);
}

// Get DTCs by system
export function getDTCsBySystem(system: string): DTCCode[] {
  return Object.values(DTC_CODES).filter(d => d.systems.includes(system));
}

// Get DTCs by prefix (e.g., 'P0A', 'C0', 'U0')
export function getDTCsByPrefix(prefix: string): DTCCode[] {
  const upperPrefix = prefix.toUpperCase();
  return Object.values(DTC_CODES).filter(d => d.code.startsWith(upperPrefix));
}
